<template>
    <div class="login-container">
      <!--登录面板内容部分-->
      <div class="login-inner">
        <!--面板头部-->
        <div class="login-header">
          <h1>矿业大学ATM系统</h1>
          <div class="login-logo">
            <img :src="logo" alt="" width="70%">
          </div>
          
        </div>
        <!--面板表单部分-->
        <div class="login-content">
          <!--账号登录部分-->
          <el-form :label-position="'right'" label-width="80px">
            <el-form-item label="账号">
              <el-input v-model.trim="form.name" placeholder="账号"></el-input>
            </el-form-item>
            <el-form-item label="密码">
              <el-input show-password v-model.trim="form.password" placeholder="密码"></el-input>
            </el-form-item>
            <el-form-item label="确认密码">
              <el-input show-password v-model.trim="form.confirm_password" placeholder="确认密码"></el-input>
            </el-form-item>
            <el-form-item label="手机">
              <el-input v-model.trim="form.tel" placeholder="手机号"></el-input>
            </el-form-item>
            <el-form-item label="年龄">
              <el-input v-model.trim="form.age" placeholder="年龄"></el-input>
            </el-form-item>
            <el-form-item label="身份证号">
              <el-input v-model.trim="form.identity_cardid" placeholder="身份证号"></el-input>
            </el-form-item>
           
            <el-form-item label="">
              <div style="text-align: center;">
                <el-button style="padding: 7px 15px;" type="primary" @click="registerFun()">注册</el-button>
                <el-button style="padding: 7px 15px;" type="primary" @click="goTo('/login')">返回登录</el-button>
              </div>
            </el-form-item>
          </el-form>
        </div>
      </div>
    </div>
  </template>
  
  <script>
   import {
    register, // 注册
  } from '@/api/index'
    import { mapState, mapGetters } from 'vuex';
  
    export default {
      name: "Login",
      data() {
        return {
          form: {
            name: '',

          },
          pwdMode: true, // 密码的显示方式 true 密文 false 明文
          password: '', // 密码
          password2: '', // 密码
          username: '', // 账号
          telephone: '', // 手机
          userType: 2,
          adminInfo: {},
          logo: require("@/assets/logo.png"), // logo图片
        }
      },
      methods: {
        // 注册
        async registerFun(){
            if(!this.form.name){
                this.$message.warning('请填写账号')
                return
            }
            if(!this.form.tel){
                this.$message.warning('请填写手机号')
                return
            }
            const reg = /^[1][3,4,5,6,7,8,9][0-9]{9}$/;
            if (!reg.test(this.form.tel)) {
                this.$message.warning('手机号格式错误')
                return;
            }
            if(!this.form.password){
                this.$message.warning('请填写密码')
                return
            }
            if(this.form.password != this.form.confirm_password){
                this.$message.warning('两次密码不相同')
                return;
            }
            let page = {...this.form}
            let result = this.userType == 2? await register(page): await register(page)
            if(result['注册']){
                this.$message.success('注册成功，3秒后跳转到登录页;' + '卡号是：', + result['卡号'])
                setTimeout(() => {
                    this.$router.push('/login');
                }, 3000);
            }else {
              this.$message.warning(JSON.stringify(result))
            }
            
        },
        // 跳转
        goTo(path){
            this.$router.push(path);
        }
      }
    }
  </script>
  
  <style scoped lang="stylus" rel="stylesheet/stylus">
    @import "../../common/stylus/mixins.styl"
    .login-container::before {   // div是你需要添加背景图片的盒子
        content: "";
        background-image:  url('./images/bg.jpg');  // 背景图片的路径
        opacity: 0.9;
        background-size: 100% 100%;
        width: 100vw;
        height: 100vh;
        content: "";
        position: absolute;
        top: 0;
        left: 0;
        z-index: -1;/*-1 可以当背景*/
        -webkit-filter: blur(3px);
        filter: blur(3px);
      }
    .login-container
      width 100%
      height 100%
      opacity: 1;
      position relative
      
      .login-inner
        margin: 0 auto;
        padding-top 5vh
        width 550px
        .login-header
          text-align: center
          color: white
          h1 {
            margin: 10px 0;
            font-family: cursive
            font-size: 3rem
          }
          .login-logo
            font-size 20px
            font-weight bold
            color mediumpurple
            text-align center

            >img {
              border-radius: 20px
              margin: 20px;
            }
            
            > a
              color #333
              font-size 14px
              padding-bottom 4px
              &:first-child
                margin-right 40px
              &.current
                color mediumpurple
                font-weight 700
                -bottom 2px solid mediumpurple
        .login-content
            margin: 10px;
            background-color: white;
            -radius: 5px;
            padding: 20px
            border-radius: 20px
  </style>
  


